// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const jobList=$("移除重复工单").all().map(e=>e.json);
for (const item of $input.all()) {
  const list=item.json.list;
  list.map(e=>{
    if(e.MTART=='Z001'){
       const sale_location=checkString(e.MAKTX_ZH);
      jobList.map(el=>{
        if(el.materialCode==e.MATNR){
          el.sale_location=sale_location;
        }
      })

    }
  })
}
//检查是否包含国内或者海外字段
function checkString(str) {
          const hasDomestic = str.includes('国内')||str.includes('无锡款');
    const hasOverseas = str.includes('海外')||str.includes('日韩');

    if (hasDomestic && hasOverseas) {
        // 如果同时包含"国内"和"海外"，根据需求决定返回值
        // 这里假设优先返回"国内"的值
        return 1;
    } else if (hasDomestic) {
        return 1;
    } else if (hasOverseas) {
        return 2;
    } else {
        return 0;
    }
}
return {
  jobList:jobList.filter(e=>e.sale_location)
};
